import { useEffect, useState } from "react";
import axios from "axios";
import profile from "../assets/nisha.jpg";

function AuthLayout({ children }) {
  const [stats, setStats] = useState({
    visitors: 0,
    projects: 0,
    resume: 0,
    logins: 0,
  });

  useEffect(() => {
    const loadStats = async () => {
      try {
        const res = await axios.get(
          "http://localhost:5000/api/analytics/stats",
        );
        setStats(res.data);
      } catch (err) {
        console.log("analytics error");
      }
    };

    // visitor tracking
    axios.post("http://localhost:5000/api/analytics/visit", {
      page: "auth",
      browser: navigator.userAgent,
    });

    loadStats();
  }, []);

  return (
    <div
      style={{
        display: "flex",
        padding: "120px",
        gap: "80px",
      }}
    >
      {/* LEFT SIDE */}

      <div style={{ width: "320px", textAlign: "center" }}>
        <img
          src={profile}
          alt="Nisha"
          style={{
            width: "180px",
            height: "180px",
            borderRadius: "50%",
            objectFit: "cover",
          }}
        />

        <h2>Nisha Yadav</h2>

        <p>
          I am a MERN Stack Developer passionate about building modern web
          applications using React, Node.js and MongoDB.
        </p>

        {/* ANALYTICS */}

        <div style={{ marginTop: "25px" }}>
          <div style={cardStyle}>Visitors : {stats.visitors}</div>

          <div style={cardStyle}>Project Clicks : {stats.projects}</div>

          <div style={cardStyle}>Resume Downloads : {stats.resume}</div>

          <div style={cardStyle}>Login History : {stats.logins}</div>
        </div>
      </div>

      {/* RIGHT SIDE */}

      <div
        style={{
          border: "1px solid #ddd",
          padding: "30px",
          borderRadius: "10px",
          width: "350px",
        }}
      >
        {children}
      </div>
    </div>
  );
}

const cardStyle = {
  border: "1px solid #ddd",
  padding: "10px",
  marginBottom: "10px",
  borderRadius: "6px",
  background: "#f7f7f7",
};

export default AuthLayout;
